import{_ as s,o as e,c as a,a5 as t}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：离散比例积分控制器（discrete proportional-integral controller / discrete PI）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：离散比例积分控制器（discrete proportional-integral controller / discrete PI）","tags":["power-electronics"],"status":"learning","summary":"离散比例积分控制器（discrete proportional-integral controller / discrete PI）是在固定控制周期内，根据误差计算控制输出的最常见闭环控制器之一。"},"headers":[],"relativePath":"content/power/concepts/power-electronics/discrete-pi-boost.md","filePath":"content/power/concepts/power-electronics/discrete-pi-boost.md","lastUpdated":null}'),l={name:"content/power/concepts/power-electronics/discrete-pi-boost.md"};function o(n,i,p,r,d,h){return e(),a("div",null,[...i[0]||(i[0]=[t(`<h1 id="概念-离散比例积分控制器-discrete-proportional-integral-controller-discrete-pi" tabindex="-1">概念：离散比例积分控制器（discrete proportional-integral controller / discrete PI） <a class="header-anchor" href="#概念-离散比例积分控制器-discrete-proportional-integral-controller-discrete-pi" aria-label="Permalink to &quot;概念：离散比例积分控制器（discrete proportional-integral controller / discrete PI）&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>离散比例积分控制器（discrete proportional-integral controller / discrete PI）是在固定控制周期内，根据误差计算控制输出的最常见闭环控制器之一。</p><p>在 Boost 电压闭环里，误差通常是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>e[k] = Vref - Vout[k]</span></span></code></pre></div><p>控制器输出通常会转换成占空比命令（duty command / D）。</p><h2 id="_2-不间断电源为什么需要它" tabindex="-1">2. 不间断电源为什么需要它 <a class="header-anchor" href="#_2-不间断电源为什么需要它" aria-label="Permalink to &quot;2. 不间断电源为什么需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）里大量控制目标都需要闭环：</p><ul><li>直流母线电压（DC bus voltage）要稳定。</li><li>功率因数校正（power factor correction / PFC）电流要跟踪参考。</li><li>逆变器（inverter）输出电压要跟踪正弦参考。</li><li>电池充放电电流要受限。</li></ul><p>PI 控制器是很多 UPS C 语言工程的基础构件。你读控制中断服务程序（control interrupt service routine / control ISR）时，经常会看到误差计算、积分累加、限幅和占空比更新。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>比例项（proportional term / P）像“看到误差就立刻推一把”。误差越大，推得越大。</p><p>积分项（integral term / I）像“记账”。如果输出电压长期低于参考值，积分会不断累加，让占空比逐渐增加，直到稳态误差被消除。</p><p>占空比不能无限大，所以必须有限幅。积分项也不能无限累加，否则输出饱和后还继续积累，恢复时会很慢，这就是积分饱和或积分 windup。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>位置式离散 PI 的一种常见写法：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>e[k] = Vref - Vout[k]</span></span>
<span class="line"><span>I[k] = clamp(I[k-1] + Ki * e[k] * Ts, I_min, I_max)</span></span>
<span class="line"><span>u[k] = clamp(Kp * e[k] + I[k], D_min, D_max)</span></span></code></pre></div><p>其中：</p><ul><li><code>Ts</code>：控制周期（control period）。</li><li><code>Kp</code>：比例增益（proportional gain）。</li><li><code>Ki</code>：积分增益（integral gain）。</li><li><code>u[k]</code>：控制输出，这里对应占空比命令。</li><li><code>clamp</code>：限幅函数。</li><li><code>D_min</code>、<code>D_max</code>：占空比上下限。</li></ul><h2 id="_5-仿真观察" tabindex="-1">5. 仿真观察 <a class="header-anchor" href="#_5-仿真观察" aria-label="Permalink to &quot;5. 仿真观察&quot;">​</a></h2><p>使用脚本：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/python/boost_discrete_pi.py</span></span></code></pre></div><p>图中观察三件事：</p><ul><li>输出电压 <code>Vout</code> 是否接近参考电压 <code>Vref</code>。</li><li>电压误差 <code>e</code> 是否逐渐接近 0。</li><li>占空比命令 <code>D</code> 是否在上下限内变化。</li></ul><p>当前模型是教学用平均模型，不是完整开关模型。它的目的是让你看懂闭环软件结构，而不是替代真实电源设计。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>在 C 语言固件中，PI 通常出现在控制 ISR 里。这里的采样通常来自模数转换器（analog-to-digital converter / ADC），输出通常落到脉宽调制（pulse-width modulation / PWM）占空比：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>读取 ADC -&gt; 标幺化/滤波 -&gt; 计算误差 -&gt; PI 更新 -&gt; 限幅 -&gt; 更新 PWM 占空比</span></span></code></pre></div><p>读代码时要重点看：</p><ul><li>误差的符号：是 <code>Vref - Vout</code> 还是 <code>Vout - Vref</code>。</li><li>积分项单位：是否乘了控制周期 <code>Ts</code>。</li><li>限幅位置：先限积分，还是只限最终输出。</li><li>饱和处理：输出到达上限或下限时，积分是否继续累加。</li><li>占空比更新：当前周期立即生效，还是下个更新事件生效。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：比例增益越大越快越好。<br> 正确理解：过大的比例增益会导致振荡、噪声放大或占空比频繁打限。</p></li><li><p>错误理解：积分只要能消除稳态误差，就越大越好。<br> 正确理解：积分过大可能导致超调和饱和恢复慢。</p></li><li><p>错误理解：输出限幅就够了，积分不需要管。<br> 正确理解：输出饱和时积分继续累加，会造成 windup，必须考虑积分限幅或抗饱和。</p></li><li><p>错误理解：仿真里调好的 PI 参数可以直接放到公司产品。<br> 正确理解：教学模型只说明结构。真实参数还要考虑采样、延迟、功率级、保护、噪声和硬件限制。</p></li></ul><h2 id="_8-一个仿真任务" tabindex="-1">8. 一个仿真任务 <a class="header-anchor" href="#_8-一个仿真任务" aria-label="Permalink to &quot;8. 一个仿真任务&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_discrete_pi.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_discrete_pi.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_discrete_pi.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">kp </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.006</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ki </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">40</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_discrete_pi_slow.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\boost_discrete_pi.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">duty</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">max </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.45</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\boost_discrete_pi_limited.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>观察输出电压、参考电压、电压误差、占空比命令和占空比上下限。默认图路径是 <code>simulations/results/boost_discrete_pi.png</code>。</p><h2 id="_9-验收标准" tabindex="-1">9. 验收标准 <a class="header-anchor" href="#_9-验收标准" aria-label="Permalink to &quot;9. 验收标准&quot;">​</a></h2><ul><li>能解释误差、比例项、积分项、限幅和占空比命令的关系。</li><li>能写出位置式离散 PI 的基本公式。</li><li>能在图上指出输出电压、参考电压、误差和占空比。</li><li>能解释为什么占空比上限会导致输出电压达不到参考。</li><li>能说出读 C 代码时要检查误差符号、积分限幅和 PWM 更新时刻。</li></ul><h2 id="_10-复盘问题" tabindex="-1">10. 复盘问题 <a class="header-anchor" href="#_10-复盘问题" aria-label="Permalink to &quot;10. 复盘问题&quot;">​</a></h2><ul><li>打开 <code>simulations/results/boost_discrete_pi.png</code>，最终输出电压和参考电压相差多少？最终占空比是多少？</li><li>运行 <code>--duty-max 0.45</code> 后，如果输出达不到 96 V，是 PI 算法坏了，还是执行器限幅导致的？</li><li>如果 C 代码里误差写成 <code>Vout - Vref</code>，但 PI 输出仍直接加到占空比上，会发生什么？</li></ul><h2 id="_11-导师问题" tabindex="-1">11. 导师问题 <a class="header-anchor" href="#_11-导师问题" aria-label="Permalink to &quot;11. 导师问题&quot;">​</a></h2><ul><li>我用 <code>boost_discrete_pi.py</code> 看到默认参数下最终输出约 96 V，占空比约 0.488。公司代码里的 Boost 或功率因数校正（power factor correction / PFC）电压环 PI 是位置式还是增量式？</li><li>我在脚本里对占空比和积分项都做了限幅。公司工程里抗积分饱和通常怎么写，是否有统一 PI 模块？</li><li>如果 ADC 采样值和 PWM 更新之间有一拍延迟，公司代码中会在 PI 参数整定时显式考虑这个延迟吗？</li></ul>`,42)])])}const u=s(l,[["render",o]]);export{k as __pageData,u as default};
